def simulate_pid(Kp, Ki, Kd, t, plant_num, plant_den):
    dt = t[1] - t[0]
    n = len(t)

    sys_plant = signal.TransferFunction(plant_num, plant_den)
    sys_ss = sys_plant.to_ss()
    A, B, C, D = sys_ss.A, sys_ss.B, sys_ss.C, sys_ss.D

    nx = A.shape[0]
    x = np.zeros(nx)

    y = np.zeros(n)
    u = np.zeros(n)
    e = np.zeros(n)
    integral = 0.0
    prev_error = 0.0

    setpoint = 1.0

    for i in range(n):
        yi = float(C @ x + D * u[i - 1]) if i > 0 else 0.0
        y[i] = yi

        error = setpoint - yi
        e[i] = error

        if i > 0:
            integral += 0.5 * (error + prev_error) * dt

        derivative = (error - prev_error) / dt if i > 0 else 0.0

        control = Kp * error + Ki * integral + Kd * derivative
        control = np.clip(control, -50, 50)
        u[i] = control

        x = x + dt * (A @ x + B.flatten() * control)

        prev_error = error

    return y, u, e

