def compute_metrics(y, t, setpoint=1.0):
    dt = t[1] - t[0]
    try:
        i10 = np.where(y >= 0.1 * setpoint)[0][0]
        i90 = np.where(y >= 0.9 * setpoint)[0][0]
        rise_time = (i90 - i10) * dt
    except IndexError:
        rise_time = float('nan')

    peak = np.max(y)
    overshoot = max(0, (peak - setpoint) / setpoint * 100)

    band = 0.02 * setpoint
    settled = np.where(np.abs(y - setpoint) > band)[0]
    if len(settled) > 0:
        settle_time = settled[-1] * dt
    else:
        settle_time = 0.0

    return rise_time, overshoot, settle_time

